1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
16	type Damage = { itemType: string; amount: number };
17	type Incident = { cause: string; damages: Damage[] };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
20	type Step = QuoteStep | ClaimStep;
21	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
22	
23	const DEDUCTIBLE_PER_DAMAGE = 100;
24	const HIGH_ENCHANTMENT_COVERAGE_THRESHOLD = 8;
25	const HIGH_ENCHANTMENT_COVERAGE_RATE = 0.5;
26	
27	const reimbursableAmount = (item: Item, damageAmount: number): number => {
28	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_COVERAGE_THRESHOLD) {
29	    return damageAmount * HIGH_ENCHANTMENT_COVERAGE_RATE;
30	  }
31	  return damageAmount;
32	};
33	
34	const claimStep = (step: ClaimStep, policyItems: Item[]): { payout: number } => {
35	  for (const d of step.incident.damages) {
36	    if (d.amount < 0) {
37	      throw new Error(`Damage amount cannot be negative: ${d.amount}`);
38	    }
39	  }
40	  const damageCounts = new Map<string, number>();
41	  for (const d of step.incident.damages) {
42	    damageCounts.set(d.itemType, (damageCounts.get(d.itemType) ?? 0) + 1);
43	  }
44	  for (const [itemType, count] of damageCounts) {
45	    const policyCount = policyItems.filter((i) => i.type === itemType).length;
46	    if (count > policyCount) {
47	      throw new Error(`Claim has more ${itemType} damages (${count}) than insured (${policyCount})`);
48	    }
49	  }
50	  const payout = step.incident.damages.reduce((sum, d) => {
51	    const item = policyItems.find((i) => i.type === d.itemType);
52	    if (item === undefined) {
53	      throw new Error(`Claim references item type not in policy: ${d.itemType}`);
54	    }
55	    const reimbursable = reimbursableAmount(item, d.amount);
56	    return sum + (reimbursable - DEDUCTIBLE_PER_DAMAGE);
57	  }, 0);
58	  return { payout: Math.floor(payout) };
59	};
60	
61	const itemBasePremium = (item: Item): number => {
62	  const base = BASE_PREMIUMS[item.type];
63	  if (base === undefined) {
64	    throw new Error(`Unknown item type: ${item.type}`);
65	  }
66	  return base;
67	};
68	
69	const BLOCK_SIZE = 3;
70	const COMPONENT_BLOCK_PRICE = 60;
71	
72	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
73	
74	const sumItemBasePremiums = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
76	
77	const groupByType = (items: Item[]): Map<string, Item[]> => {
78	  const groups = new Map<string, Item[]>();
79	  for (const item of items) {
80	    const group = groups.get(item.type) ?? [];
81	    group.push(item);
82	    groups.set(item.type, group);
83	  }
84	  return groups;
85	};
86	
87	const priceComponentGroup = (group: Item[]): number =>
88	  group.length === BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : sumItemBasePremiums(group);
89	
90	const computeBasePremium = (items: Item[]): number => {
91	  const components = items.filter(isComponent);
92	  const nonComponents = items.filter((item) => !isComponent(item));
93	  const componentGroups = [...groupByType(components).values()];
94	  const componentTotal = componentGroups.reduce(
95	    (sum, group) => sum + priceComponentGroup(group),
96	    0,
97	  );
98	  return sumItemBasePremiums(nonComponents) + componentTotal;
99	};
100	
101	const CURSE_SURCHARGE_RATE = 0.5;
102	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
103	const HIGH_ENCHANTMENT_THRESHOLD = 5;
104	
105	const itemSurcharge = (item: Item): number => {
106	  const base = itemBasePremium(item);
107	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
108	  const enchantment =
109	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
110	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
111	      : 0;
112	  return curse + enchantment;
113	};
114	
115	const sumItemSurcharges = (items: Item[]): number =>
116	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
117	
118	const LOYALTY_DISCOUNT_RATE = 0.2;
119	const LOYALTY_THRESHOLD_YEARS = 2;
120	
121	type Customer = { yearsWithMHPCO: number };
122	type PolicyContext = { customer: Customer; contractIndex: number };
123	
124	const loyaltyDiscount = (base: number, customer: Customer): number =>
125	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
126	
127	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
128	
129	const followUpDiscount = (base: number, contractIndex: number): number =>
130	  contractIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
131	
132	const sumPolicyDiscounts = (base: number, ctx: PolicyContext): number =>
133	  loyaltyDiscount(base, ctx.customer) + followUpDiscount(base, ctx.contractIndex);
134	
135	const sumPolicySurcharges = (base: number): number => base * FIRST_INSURANCE_RATE;
136	
137	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
138	  const base = computeBasePremium(step.items);
139	  const surcharges = sumItemSurcharges(step.items) + sumPolicySurcharges(base);
140	  const discounts = sumPolicyDiscounts(base, ctx);
141	  return {
142	    premium: Math.ceil(base + surcharges - discounts + PROCESSING_FEE),
143	  };
144	};
145	
146	export const runScenario = (scenario: unknown): unknown => {
147	  const { customer, steps } = scenario as Scenario;
148	  let contractIndex = 0;
149	  const policies = new Map<number, Item[]>();
150	  const results = steps.map((step, index) => {
151	    if (step.op === "claim") {
152	      const policyItems = policies.get(step.policy) ?? [];
153	      return claimStep(step, policyItems);
154	    }
155	    policies.set(index, step.items);
156	    const result = quoteStep(step, { customer, contractIndex });
157	    contractIndex += 1;
158	    return result;
159	  });
160	  return { results };
161	};
